package com.example.debug;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.ServerInterceptor;
import io.grpc.ServerCall;
import io.grpc.ServerCallHandler;
import io.grpc.Metadata;
import io.grpc.ForwardingServerCall;
import io.grpc.Status;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;
import java.util.logging.Logger;

public class DebugGrpcServer {

    private static final Logger logger = Logger.getLogger(DebugGrpcServer.class.getName());

    private Server server;
    private final int port;

    public DebugGrpcServer(int port) {
        this.port = port;
    }

    public void start() throws IOException {
        server = ServerBuilder.forPort(port)
                .addService(new DebugServiceImpl())
                .intercept(new DetailedErrorInterceptor())
                .build()
                .start();

        logger.info("Debug gRPC Server started on port " + port);

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            logger.info("Shutting down gRPC server");
            DebugGrpcServer.this.stop();
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    /**
     * Server interceptor that catches any unhandled exceptions and wraps them
     * with full debug information.
     */
    static class DetailedErrorInterceptor implements ServerInterceptor {
        @Override
        public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
                ServerCall<ReqT, RespT> call,
                Metadata headers,
                ServerCallHandler<ReqT, RespT> next) {

            ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
                @Override
                public void close(Status status, Metadata trailers) {
                    if (!status.isOk() && status.getCause() != null) {
                        // Log the full exception details
                        Throwable cause = status.getCause();
                        logger.severe("gRPC call failed: " + call.getMethodDescriptor().getFullMethodName()
                                + "\nStatus: " + status.getCode()
                                + "\nDescription: " + status.getDescription()
                                + "\nException: " + cause.getClass().getName()
                                + "\nMessage: " + cause.getMessage()
                                + "\nStack Trace:\n" + ErrorDetailHelper.getFullStackTrace(cause));

                        // Enhance the status with more details if it's a plain status
                        if (status.getDescription() == null || status.getDescription().isEmpty()) {
                            Map<String, String> state = new HashMap<>();
                            state.put("method", call.getMethodDescriptor().getFullMethodName());
                            state.put("interceptor", "DetailedErrorInterceptor");
                            state.put("original_status_code", status.getCode().name());

                            // Add exception details to the metadata/trailers
                            Metadata.Key<String> debugKey = Metadata.Key.of(
                                    "x-debug-exception", Metadata.ASCII_STRING_MARSHALLER);
                            Metadata.Key<String> stackTraceKey = Metadata.Key.of(
                                    "x-debug-stacktrace", Metadata.ASCII_STRING_MARSHALLER);
                            Metadata.Key<String> hostKey = Metadata.Key.of(
                                    "x-debug-host", Metadata.ASCII_STRING_MARSHALLER);
                            Metadata.Key<String> timestampKey = Metadata.Key.of(
                                    "x-debug-timestamp", Metadata.ASCII_STRING_MARSHALLER);

                            trailers.put(debugKey, cause.getClass().getName() + ": " + cause.getMessage());
                            trailers.put(stackTraceKey, ErrorDetailHelper.getFullStackTrace(cause));
                            trailers.put(hostKey, ErrorDetailHelper.getHostInfo());
                            trailers.put(timestampKey, java.time.Instant.now().toString());

                            status = status.withDescription(
                                    "Unhandled exception: " + cause.getClass().getName()
                                            + ": " + cause.getMessage()
                                            + " | Method: " + call.getMethodDescriptor().getFullMethodName()
                                            + " | Host: " + ErrorDetailHelper.getHostInfo()
                                            + " | Time: " + java.time.Instant.now());
                        }
                    }
                    super.close(status, trailers);
                }
            };

            ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

            return new io.grpc.ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
                @Override
                public void onHalfClose() {
                    try {
                        super.onHalfClose();
                    } catch (Exception e) {
                        logger.severe("Interceptor caught unhandled exception: "
                                + ErrorDetailHelper.getFullStackTrace(e));

                        Map<String, String> state = new HashMap<>();
                        state.put("method", call.getMethodDescriptor().getFullMethodName());
                        state.put("interceptor_catch", "true");
                        state.put("exception_type", e.getClass().getName());

                        wrappedCall.close(
                                Status.INTERNAL.withDescription(
                                        "Unhandled server exception: " + e.getClass().getName()
                                                + ": " + e.getMessage()
                                                + "\nFull stack trace: " + ErrorDetailHelper.getFullStackTrace(e)
                                                + "\nHost: " + ErrorDetailHelper.getHostInfo()
                                                + "\nTime: " + java.time.Instant.now()
                                ).withCause(e),
                                new Metadata());
                    }
                }
            };
        }
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        DebugGrpcServer server = new DebugGrpcServer(50051);
        server.start();
        server.blockUntilShutdown();
    }
}


