import com.google.rpc.ErrorInfo;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.util.concurrent.TimeUnit;
import java.util.logging.Logger;

public class DebugGrpcClient {

    private static final Logger logger = Logger.getLogger(DebugGrpcClient.class.getName());

    private final ManagedChannel channel;
    private final DebugServiceGrpc.DebugServiceBlockingStub blockingStub;

    public DebugGrpcClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .build();
        blockingStub = DebugServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void getUser(String userId) {
        logger.info("Requesting user: " + userId);

        GetUserRequest request = GetUserRequest.newBuilder()
                .setUserId(userId)
                .build();

        try {
            GetUserResponse response = blockingStub.getUser(request);
            logger.info("Got user: " + response.getUserId()
                    + ", name=" + response.getName()
                    + ", email=" + response.getEmail());
        } catch (StatusRuntimeException e) {
            handleDetailedError(e);
        }
    }

    public void updateUser(String userId, String name, String email) {
        logger.info("Updating user: " + userId);

        UpdateUserRequest request = UpdateUserRequest.newBuilder()
                .setUserId(userId)
                .setName(name)
                .setEmail(email)
                .build();

        try {
            UpdateUserResponse response = blockingStub.updateUser(request);
            logger.info("Update success: " + response.getSuccess());
        } catch (StatusRuntimeException e) {
            handleDetailedError(e);
        }
    }

    public void queryDatabase(String sql) {
        logger.info("Executing query: " + sql);

        QueryRequest request = QueryRequest.newBuilder()
                .setSql(sql)
                .build();

        try {
            QueryResponse response = blockingStub.queryDatabase(request);
            logger.info("Query returned " + response.getRowsCount() + " rows");
            for (String row : response.getRowsList()) {
                logger.info("  Row: " + row);
            }
        } catch (StatusRuntimeException e) {
            handleDetailedError(e);
        }
    }

    private void handleDetailedError(StatusRuntimeException e) {
        logger.severe("=== DETAILED ERROR REPORT ===");
        logger.severe("Status Code: " + e.getStatus().getCode());
        logger.severe("Status Description: " + e.getStatus().getDescription());
        logger.severe("Status Cause: " + (e.getStatus().getCause() != null
                ? e.getStatus().getCause().getMessage() : "none"));

        // Extract rich error details from the Status proto
        com.google.rpc.Status status = StatusProto.fromThrowable(e);
        if (status != null) {
            logger.severe("Proto Status Code: " + status.getCode());
            logger.severe("Proto Status Message: " + status.getMessage());

            for (Any detail : status.getDetailsList()) {
                try {
                    if (detail.is(DebugInfo.class)) {
                        DebugInfo debugInfo = detail.unpack(DebugInfo.class);
                        logger.severe("--- Debug Info ---");
                        logger.severe("Detail: " + debugInfo.getDetail());
                        logger.severe("Stack Entries:");
                        for (String entry : debugInfo.getStackEntriesList()) {
                            logger.severe("  at " + entry);
                        }
                    } else if (detail.is(ErrorInfo.class)) {
                        ErrorInfo errorInfo = detail.unpack(ErrorInfo.class);
                        logger.severe("--- Error Info ---");
                        logger.severe("Reason: " + errorInfo.getReason());
                        logger.severe("Domain: " + errorInfo.getDomain());
                        logger.severe("Metadata:");
                        errorInfo.getMetadataMap().forEach((key, value) ->
                                logger.severe("  " + key + " = " + value));
                    } else if (detail.is(BadRequest.class)) {
                        BadRequest badRequest = detail.unpack(BadRequest.class);
                        logger.severe("--- Bad Request ---");
                        for (BadRequest.FieldViolation violation : badRequest.getFieldViolationsList()) {
                            logger.severe("  Field: " + violation.getField()
                                    + " - " + violation.getDescription());
                        }
                    }
                } catch (InvalidProtocolBufferException ex) {
                    logger.severe("Failed to unpack error detail: " + ex.getMessage());
                }
            }
        }

        // Also check trailing metadata for debug headers
        io.grpc.Metadata trailers = e.getTrailers();
        if (trailers != null) {
            io.grpc.Metadata.Key<String> debugExKey = io.grpc.Metadata.Key.of(
                    "x-debug-exception", io.grpc.Metadata.ASCII_STRING_MARSHALLER);
            io.grpc.Metadata.Key<String> stackKey = io.grpc.Metadata.Key.of(
                    "x-debug-stacktrace", io.grpc.Metadata.ASCII_STRING_MARSHALLER);
            io.grpc.Metadata.Key<String> hostKey = io.grpc.Metadata.Key.of(
                    "x-debug-host", io.grpc.Metadata.ASCII_STRING_MARSHALLER);

            String debugEx = trailers.get(debugExKey);
            String stack = trailers.get(stackKey);
            String host = trailers.get(hostKey);

            if (debugEx != null) logger.severe("Trailer Debug Exception: " + debugEx);
            if (stack != null) logger.severe("Trailer Stack Trace: " + stack);
            if (host != null) logger.severe("Trailer Host: " + host);
        }

        logger.severe("=== END ERROR REPORT ===");
    }

    public static void main(String[] args) throws InterruptedException {
        DebugGrpcClient client = new DebugGrpcClient("localhost", 50051);

        try {
            // Test 1: Get existing user from cache
            client.getUser("user-1");

            // Test 2: Get non-existent user (will trigger NOT_FOUND with full details)
            client.getUser("user-999");

            // Test 3: Update with invalid email (will trigger validation error)
            client.updateUser("user-1", "Alice Updated", "invalid-email");

            // Test 4: Empty user ID (will trigger validation error)
            client.getUser("");

            // Test 5: Database query (will fail if no DB connection, exposing full DB error)
            client.queryDatabase("SELECT * FROM users");

        } finally {
            client.shutdown();
        }
    }
}